"""GENERATED stereo-synthesis assets — inlined so N-stereo sessions build with NO external
control files. Regenerate via `donorpack.write_stereo_data(control_root)` after re-authoring the
source controls. Sources: '8 stereo tracks.ptx' (scaffold, base_n=8, Mac/512-compatible 0x261c
layout) + '512 stereo tracks.ptx' (track-2/10/100 = 1/2/3-digit unit templates, for tracks
1-9 / 10-99 / 100-512). The per-track GUID + 160 B blob are PT-confirmed self-contained."""
import base64 as _b64, zlib as _z
from . import body_synth as _B

_SCAFFOLD = ""
_TMPL1 = ""
_TMPL2 = ""
_TMPL3 = ""

def _dec(s): return _z.decompress(_b64.b64decode(s))
def _unit(blob):
    o = 0; bs = []
    for _ in range(9):
        n = int.from_bytes(blob[o:o + 4], "little"); o += 4; bs.append(blob[o:o + n]); o += n
    return _B.StereoTrackUnit(b1014=bs[0], b1052=(bs[1], bs[2]), b251a=(bs[3], bs[4]),
                              b210b=bs[5], b261c=bs[6], b2589=bs[7], name_entry=bs[8])

def stereo_scaffold(): return _dec(_SCAFFOLD)          # 8-track Mac clean session (base_n=8)
def stereo_templates():                                # (1-digit, 2-digit, 3-digit)
    return _unit(_dec(_TMPL1)), _unit(_dec(_TMPL2)), _unit(_dec(_TMPL3))
